import{_ as t,o as l,c as e,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F07: 存貨週轉效率同業對比 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F07_存貨週轉效率同業對比.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F07_存貨週轉效率同業對比.md"}'),i={name:"審計報告庫/財務審計/3105_穩懋/20260503/F07_存貨週轉效率同業對比.md"};function o(n,a,s,h,c,_){return l(),e("div",null,[...a[0]||(a[0]=[r('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f07-存貨週轉效率同業對比-財務審計專家-審計報告" tabindex="-1">F07: 存貨週轉效率同業對比 - 財務審計專家 審計報告 <a class="header-anchor" href="#f07-存貨週轉效率同業對比-財務審計專家-審計報告" aria-label="Permalink to &quot;F07: 存貨週轉效率同業對比 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>存貨週轉天數與同業相比是否具備競爭優勢？整體營運週期 (Cash Cycle) 是否處於擴張狀態？透過對比同業存貨週轉天數，判定公司去化能力與市場議價權。</p></blockquote><h2 id="🎯-專家直斷-46-字" tabindex="-1">🎯 專家直斷（46 字） <a class="header-anchor" href="#🎯-專家直斷-46-字" aria-label="Permalink to &quot;🎯 專家直斷（46 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DIO 556 天高於同業 36.6% 居弱勢，但 DSO 36 天優於同業 61 天（-41%），一強一弱互補，CCC 406 天在低谷屬可控。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-140-字" tabindex="-1">📊 診斷評級（140 字） <a class="header-anchor" href="#📊-診斷評級-140-字" aria-label="Permalink to &quot;📊 診斷評級（140 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：同業對比：穩懋 DIO 556 天 vs 宏捷科 386 / 全新 428；DSO 36 天 vs 宏捷科 64 / 全新 57。CCC 從 508 天降至 406 天（-20.1%）。</li><li><strong>診斷見解</strong>：DIO 偏高因規模與產品複雜度，具結構性因素。DSO 優勢顯著反映議價力強。CCC 改善方向正確。</li></ul><h2 id="🔍-答詢詳解-418-字" tabindex="-1">🔍 答詢詳解（418 字） <a class="header-anchor" href="#🔍-答詢詳解-418-字" aria-label="Permalink to &quot;🔍 答詢詳解（418 字）&quot;">​</a></h2><h3 id="存貨週轉效率同業階差分析" tabindex="-1">存貨週轉效率同業階差分析 <a class="header-anchor" href="#存貨週轉效率同業階差分析" aria-label="Permalink to &quot;存貨週轉效率同業階差分析&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DIO 556 天為同業最高（宏捷科 386、全新 428），主因規模差距及原料佔比高。</li><li><strong>深度見解</strong>：以 COGS 基礎估算，穩懋 DIO 約 144 天，差距縮小至 10-31%。</li></ul><h3 id="收款效率優勢-定價權的側面證據" tabindex="-1">收款效率優勢：定價權的側面證據 <a class="header-anchor" href="#收款效率優勢-定價權的側面證據" aria-label="Permalink to &quot;收款效率優勢：定價權的側面證據&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DSO 36 天遠優於宏捷科 64 天與全新 57 天，此優勢連續三年維持。</li><li><strong>深度見解</strong>：DSO 約 30 天在台灣半導體代工業屬頂尖，部分抵消 DIO 劣勢。</li></ul><h3 id="現金循環週期趨勢-2025-年明顯改善" tabindex="-1">現金循環週期趨勢：2025 年明顯改善 <a class="header-anchor" href="#現金循環週期趨勢-2025-年明顯改善" aria-label="Permalink to &quot;現金循環週期趨勢：2025 年明顯改善&quot;">​</a></h3><ul><li><strong>核心重點</strong>：CCC 從 508 天降至 406 天（-20.1%），主因 DPO 擴至 186 天。同業宏捷科 309 天、全新 248 天仍領先。</li><li><strong>深度見解</strong>：若利用率回升至 65-70%，可望壓縮 DIO 至 350 天以下。</li></ul><h2 id="💡-專家評析-383-字-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（383 字，≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-383-字-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（383 字，≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>DIO 偏高為結構性弱勢，存貨去化彈性不足</strong>：穩懋 DIO 556 天（工具值）高於同業均值 36.6%，即使以年報 COGS 調整後仍達 144 天，高於全新（110 天）。原料庫存 NT$3.5B 佔比 70%，若下游需求驟降或規格變更（如 GaAs 轉向 GaN），大量原料將面臨減值壓力。2025 年雖有 NT$100M 跌價迴轉，但 2024 年曾提列 NT$235M 損失，反映存貨風險在景氣逆風時會顯著放大。</p></li><li><p><strong>現金循環週期落後同業，營運資金效率待提升</strong>：穩懋 CCC 406 天遠不及宏捷科 309 天（+31.4%）與全新 248 天（+63.7%），差距來自 DIO 過高。每多 1 天 CCC 意味著多佔用 NT$45.6M 營運資金（以日均營收計）。406 天 CCC 與同業的差值（約 100-158 天）代表額外營運資金佔用 NT$4.6-7.2B，資金效率偏低。</p></li><li><p><strong>DPO 壓縮供應商付款天數有極限</strong>：DPO 從 135 天擴至 186 天，已接近產業合理上限。若持續擠壓供應商付款週期，可能導致關鍵原料供應商縮減供貨或轉單，尤其在全球 GaAs 磊晶片供應集中於 IQE、全新等少數供應商的背景下，供應鏈關係風險不容忽視。2026 年 DPO 若反向收縮，將直接推升 CCC。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (inventory_check 3105、inventory_check 8086、inventory_check 2455 各 2023-2025)</li><li>原始數據：FinMind TaiwanStockBalanceSheet、TaiwanStockFinancialStatements</li><li>年報 PDF：2025_Q4_3105_合併.pdf（存貨明細附註 p.7-8）</li><li>查詢參數：stock_id=3105|8086|2455, start=2023-01-01, end=2025-12-31</li><li>關鍵核對碼：穩懋 DIO=556/DSO=36/DPO=186/CCC=406; 宏捷科 DIO=386/DSO=64/CCC=309; 全新 DIO=428/DSO=57/CCC=248</li></ul>',19)])])}const C=t(i,[["render",o]]);export{u as __pageData,C as default};
